   239→asyncmeta_back_add( Operation *op, SlapReply *rs )
   240→{
   241→	a_metainfo_t	*mi = ( a_metainfo_t * )op->o_bd->be_private;
   242→	a_metatarget_t	*mt;
   243→	a_metaconn_t	*mc;
   244→	int		rc, candidate = -1;
   245→	void *thrctx = op->o_threadctx;
   246→	bm_context_t *bc;
   247→	SlapReply *candidates;
   248→	time_t current_time = slap_get_time();
   249→	int max_pending_ops = (mi->mi_max_pending_ops == 0) ? META_BACK_CFG_MAX_PENDING_OPS : mi->mi_max_pending_ops;
   250→
   251→	Debug(LDAP_DEBUG_TRACE, "==> asyncmeta_back_add: %s\n",
   252→	      op->o_req_dn.bv_val );
   253→
   254→	if (current_time > op->o_time) {
   255→		Debug(asyncmeta_debug, "==> asyncmeta_back_add[%s]: o_time:[%ld], current time: [%ld]\n",
   256→		      op->o_log_prefix, op->o_time, current_time );
   257→	}
   258→
   259→	if ( mi->mi_ntargets == 0 ) {
   260→		rs->sr_err = LDAP_UNWILLING_TO_PERFORM;
   261→		rs->sr_text = "No targets are configured for this database";
   262→		send_ldap_result(op, rs);
   263→		return rs->sr_err;
   264→	}
   265→
   266→	asyncmeta_new_bm_context(op, rs, &bc, mi->mi_ntargets, mi );
   267→	if (bc == NULL) {
   268→		rs->sr_err = LDAP_OTHER;
   269→		send_ldap_result(op, rs);
   270→		return rs->sr_err;
   271→	}
   272→
   273→	candidates = bc->candidates;
   274→	mc = asyncmeta_getconn( op, rs, candidates, &candidate, LDAP_BACK_DONTSEND, 0);
   275→	if ( !mc || rs->sr_err != LDAP_SUCCESS) {
   276→		send_ldap_result(op, rs);
   277→		return rs->sr_err;
   278→	}
   279→
   280→	mt = mi->mi_targets[ candidate ];
   281→	bc->timeout = mt->mt_timeout[ SLAP_OP_ADD ];
   282→	bc->retrying = LDAP_BACK_RETRYING;
   283→	bc->sendok = ( LDAP_BACK_SENDRESULT | bc->retrying );
   284→	bc->stoptime = op->o_time + bc->timeout;
   285→	bc->bc_active = 1;
   286→
   287→	if (mc->pending_ops >= max_pending_ops) {
   288→		rs->sr_err = LDAP_BUSY;
   289→		rs->sr_text = "Maximum pending ops limit exceeded";
   290→		send_ldap_result(op, rs);
   291→		return rs->sr_err;
   292→	}
   293→
   294→	ldap_pvt_thread_mutex_lock( &mc->mc_om_mutex);
   295→	rc = asyncmeta_add_message_queue(mc, bc);
   296→	mc->mc_conns[candidate].msc_active++;
   297→	ldap_pvt_thread_mutex_unlock( &mc->mc_om_mutex);
   298→
   299→	if (rc != LDAP_SUCCESS) {
   300→		rs->sr_err = LDAP_BUSY;
   301→		rs->sr_text = "Maximum pending ops limit exceeded";
   302→		send_ldap_result(op, rs);
   303→		ldap_pvt_thread_mutex_lock( &mc->mc_om_mutex);
   304→		mc->mc_conns[candidate].msc_active--;
   305→		ldap_pvt_thread_mutex_unlock( &mc->mc_om_mutex);
   306→		goto finish;
   307→	}
   308→
   309→retry:
   310→	current_time = slap_get_time();
   311→	if (bc->timeout && bc->stoptime < current_time) {
   312→		int		timeout_err;
   313→		timeout_err = op->o_protocol >= LDAP_VERSION3 ?
   314→			LDAP_ADMINLIMIT_EXCEEDED : LDAP_OTHER;
   315→		rs->sr_err = timeout_err;
   316→		rs->sr_text = "Operation timed out before it was sent to target";
   317→		asyncmeta_error_cleanup(op, rs, bc, mc, candidate);
   318→		goto finish;
   319→	}
   320→
   321→	rc = asyncmeta_dobind_init_with_retry(op, rs, bc, mc, candidate);
   322→	switch (rc)
   323→	{
   324→	case META_SEARCH_CANDIDATE:
   325→		/* target is already bound, just send the request */
   326→		Debug(LDAP_DEBUG_TRACE , "%s asyncmeta_back_add:  "
   327→		       "cnd=\"%d\"\n", op->o_log_prefix, candidate );
   328→
   329→		rc = asyncmeta_back_add_start( op, rs, mc, bc, candidate, 1);
   330→		if (rc == META_SEARCH_ERR) {
   331→			asyncmeta_error_cleanup(op, rs, bc, mc, candidate);
   332→			goto finish;
   333→
   334→		} else if (rc == META_SEARCH_NEED_BIND) {
   335→			goto retry;
   336→		}
   337→		break;
   338→	case META_SEARCH_NOT_CANDIDATE:
   339→		Debug( LDAP_DEBUG_TRACE, "%s asyncmeta_back_add: NOT_CANDIDATE "
   340→		       "cnd=\"%d\"\n", op->o_log_prefix, candidate );
   341→		asyncmeta_error_cleanup(op, rs, bc, mc, candidate);
   342→		goto finish;
   343→
   344→	case META_SEARCH_NEED_BIND:
   345→	case META_SEARCH_BINDING:
   346→		Debug( LDAP_DEBUG_TRACE, "%s asyncmeta_back_add: BINDING "
   347→		       "cnd=\"%d\" %p\n", op->o_log_prefix, candidate , &mc->mc_conns[candidate]);
   348→		/* add the context to the message queue but do not send the request
   349→		   the receiver must send this when we are done binding */
   350→		break;
   351→
   352→	case META_SEARCH_ERR:
   353→		Debug( LDAP_DEBUG_TRACE, "%s asyncmeta_back_add: ERR "
   354→		       "cnd=\"%d\"\n", op->o_log_prefix, candidate );
   355→		asyncmeta_error_cleanup(op, rs, bc, mc, candidate);
   356→		goto finish;
   357→	default:
   358→		assert( 0 );
   359→		break;
   360→	}
   361→
   362→	ldap_pvt_thread_mutex_lock( &mc->mc_om_mutex);
   363→	mc->mc_conns[candidate].msc_active--;
   364→	asyncmeta_start_one_listener(mc, candidates, bc, candidate);
   365→	bc->bc_active--;
   366→	ldap_pvt_thread_mutex_unlock( &mc->mc_om_mutex);
   367→	rs->sr_err = SLAPD_ASYNCOP;
   368→finish:
   369→	return rs->sr_err;
   370→}
